<?php
declare(strict_types=1);

require_once $_SERVER['DOCUMENT_ROOT'] . '/ntn_erp/config/auth.php';
require_once $_SERVER['DOCUMENT_ROOT'] . '/ntn_erp/config/database.php';
require_once $_SERVER['DOCUMENT_ROOT'] . '/ntn_erp/config/functions.php';

requireLogin();

$requestedUserId = (int) ($_GET['user_id'] ?? $_SESSION['user_id']);
$isPrivilegedViewer = in_array($_SESSION['role'], ['director', 'accountant', 'manager'], true);
$userId = $isPrivilegedViewer ? $requestedUserId : (int) $_SESSION['user_id'];

$statement = $pdo->prepare('SELECT u.*, r.name AS role_name, r.display_name AS role_display_name, d.name AS department_name FROM users u LEFT JOIN roles r ON r.id = u.role_id LEFT JOIN departments d ON d.id = u.department_id WHERE u.id = :id LIMIT 1');
$statement->execute(['id' => $userId]);
$profile = $statement->fetch();
if (!$profile) {
    setFlash('danger', 'Không tìm thấy hồ sơ nhân viên.');
    redirect('dashboard.php');
}

$attendanceStats = fetchOneSafe($pdo, 'SELECT COUNT(*) AS days_worked, COALESCE(SUM(CASE WHEN status = :late THEN 1 ELSE 0 END), 0) AS late_count FROM attendance_logs WHERE user_id = :user_id AND MONTH(work_date) = MONTH(CURDATE()) AND YEAR(work_date) = YEAR(CURDATE())', ['late' => 'late', 'user_id' => $userId], ['days_worked' => 0, 'late_count' => 0]);
$attendanceRows = fetchAllSafe($pdo, 'SELECT work_date, check_in, check_out, status FROM attendance_logs WHERE user_id = :user_id AND MONTH(work_date) = MONTH(CURDATE()) AND YEAR(work_date) = YEAR(CURDATE()) ORDER BY work_date DESC LIMIT 31', ['user_id' => $userId]);
$latestPayroll = fetchOneSafe($pdo, 'SELECT CONCAT(LPAD(pp.period_month, 2, "0"), "/", pp.period_year) AS pay_period, (ps.basic_salary + ps.allowances + ps.ot_amount) AS gross_salary, ps.deductions, ps.net_salary, pp.status, NULL AS paid_at FROM payroll_slips ps INNER JOIN payroll_periods pp ON pp.id = ps.period_id WHERE ps.user_id = :user_id ORDER BY pp.period_year DESC, pp.period_month DESC LIMIT 1', ['user_id' => $userId], null);
$leaveBalance = getLeaveBalance($pdo, $userId);

$pageTitle = 'Hồ sơ cá nhân';
$breadcrumbs = [['label' => 'Tổng quan', 'url' => 'dashboard.php'], ['label' => 'Hồ sơ cá nhân']];

require __DIR__ . '/../../includes/header.php';
require __DIR__ . '/../../includes/sidebar.php';
?>
<div class="row g-4"><div class="col-lg-4"><div class="card content-card h-100"><div class="card-body p-4 text-center"><div class="avatar-circle mx-auto mb-3"><?= e(getInitials((string) $profile['full_name'])) ?></div><h1 class="h4 mb-1"><?= e($profile['full_name']) ?></h1><span class="badge text-bg-<?= e(roleBadgeClass((string) ($profile['role_name'] ?? 'employee'))) ?> mb-3"><?= e($profile['role_display_name'] ?? roleLabel((string) ($profile['role_name'] ?? 'employee'))) ?></span><div class="text-muted mb-4"><?= e($profile['department_name'] ?? 'Chưa phân phòng ban') ?></div><div class="text-start small"><div class="mb-2"><i class="fa-solid fa-id-badge me-2 text-primary"></i><strong>Mã NV:</strong> <?= e($profile['employee_code'] ?? '—') ?></div><div class="mb-2"><i class="fa-solid fa-phone me-2 text-primary"></i><strong>SĐT:</strong> <?= e($profile['phone'] ?? '—') ?></div><div class="mb-2"><i class="fa-solid fa-envelope me-2 text-primary"></i><strong>Email:</strong> <?= e($profile['email'] ?? '—') ?></div><div class="mb-2"><i class="fa-solid fa-calendar-day me-2 text-primary"></i><strong>Ngày vào làm:</strong> <?= e(formatDate($profile['hire_date'] ?? null)) ?></div><div><i class="fa-solid fa-plane-departure me-2 text-primary"></i><strong>Phép còn lại:</strong> <?= number_format((float) $leaveBalance, 1, ',', '.') ?> ngày</div></div></div></div></div><div class="col-lg-8"><div class="card content-card"><div class="card-body p-4"><ul class="nav nav-tabs mb-4" role="tablist"><li class="nav-item"><button class="nav-link active" data-bs-toggle="tab" data-bs-target="#info-tab" type="button">Thông tin cá nhân</button></li><li class="nav-item"><button class="nav-link" data-bs-toggle="tab" data-bs-target="#attendance-tab" type="button">Chấm công tháng này</button></li><li class="nav-item"><button class="nav-link" data-bs-toggle="tab" data-bs-target="#payroll-tab" type="button">Phiếu lương gần nhất</button></li></ul><div class="tab-content"><div class="tab-pane fade show active" id="info-tab"><div class="row g-3"><div class="col-md-6"><div class="rounded-4 bg-primary-subtle p-3"><div class="small text-primary-emphasis">Ngày công tháng này</div><div class="h3 fw-bold mb-0"><?= number_format((int) ($attendanceStats['days_worked'] ?? 0)) ?></div></div></div><div class="col-md-6"><div class="rounded-4 bg-warning-subtle p-3"><div class="small text-warning-emphasis">Số lần đi muộn</div><div class="h3 fw-bold mb-0"><?= number_format((int) ($attendanceStats['late_count'] ?? 0)) ?></div></div></div><div class="col-12"><div class="rounded-4 bg-light p-4"><h2 class="h6 mb-3">Thông tin liên hệ & ngân hàng</h2><div class="row g-3 small"><div class="col-md-6"><strong>Tài khoản ngân hàng:</strong> <?= e($profile['bank_account'] ?? '—') ?></div><div class="col-md-6"><strong>Ngân hàng:</strong> <?= e($profile['bank_name'] ?? '—') ?></div><div class="col-md-6"><strong>Lương cơ bản:</strong> <?= e(formatCurrency($profile['salary_base'] ?? 0)) ?></div><div class="col-md-6"><strong>Tên đăng nhập:</strong> <?= e($profile['username'] ?? '—') ?></div></div></div></div></div></div><div class="tab-pane fade" id="attendance-tab"><div class="table-responsive"><table class="table align-middle"><thead class="table-light"><tr><th>Ngày</th><th>Check-in</th><th>Check-out</th><th>Trạng thái</th></tr></thead><tbody><?php if ($attendanceRows === []): ?><tr><td colspan="4" class="text-center text-muted py-4">Chưa có dữ liệu chấm công trong tháng.</td></tr><?php else: ?><?php foreach ($attendanceRows as $row): ?><tr><td><?= e(formatDate($row['work_date'] ?? null)) ?></td><td><?= e(formatDateTime($row['check_in'] ?? null, 'H:i')) ?></td><td><?= e(formatDateTime($row['check_out'] ?? null, 'H:i')) ?></td><td><span class="badge text-bg-light"><?= e((string) ($row['status'] ?? '—')) ?></span></td></tr><?php endforeach; ?><?php endif; ?></tbody></table></div></div><div class="tab-pane fade" id="payroll-tab"><?php if ($latestPayroll === null): ?><div class="alert alert-light mb-0">Chưa có phiếu lương nào được ghi nhận.</div><?php else: ?><div class="row g-3"><div class="col-md-6"><strong>Kỳ lương:</strong> <?= e((string) ($latestPayroll['pay_period'] ?? '—')) ?></div><div class="col-md-6"><strong>Trạng thái:</strong> <?= e((string) ($latestPayroll['status'] ?? '—')) ?></div><div class="col-md-6"><strong>Lương gross:</strong> <?= e(formatCurrency($latestPayroll['gross_salary'] ?? 0)) ?></div><div class="col-md-6"><strong>Khấu trừ:</strong> <?= e(formatCurrency($latestPayroll['deductions'] ?? 0)) ?></div><div class="col-md-6"><strong>Thực lĩnh:</strong> <?= e(formatCurrency($latestPayroll['net_salary'] ?? 0)) ?></div><div class="col-md-6"><strong>Ngày chi trả:</strong> <?= e(formatDate($latestPayroll['paid_at'] ?? null)) ?></div></div><?php endif; ?></div></div></div></div></div></div>
<?php require __DIR__ . '/../../includes/footer.php'; ?>
